  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import { tool } from "ai";
  4→import { z } from "zod";
  5→import { ENTITY_CATEGORIES, ENTITY_PRIORITIES } from "../../../shared/contracts";
  6→import { createEmbeddingVector } from "../../graph/embeddings";
  7→import {
  8→  createExtractionProvenanceEdge,
  9→  createProjectRecord,
 10→  resolveWorkspaceProjectRecord,
 11→} from "../../graph/queries";
 12→import { seedDescriptionEntry } from "../../descriptions/persist";
 13→import { fireDescriptionUpdates } from "../../descriptions/triggers";
 14→import { ensureProjectFeatureEdge } from "../../workspace/workspace-scope";
 15→import { requireAuthorizedContext } from "../../iam/authority";
 16→import { logError } from "../../http/observability";
 17→import type { ChatToolDeps } from "./types";
 18→
 19→export function createCreateWorkItemTool(deps: ChatToolDeps) {
 20→  return tool({
 21→    description:
 22→      "Create a task, feature, or project directly in the knowledge graph. Use when the user explicitly requests creation (\"add a task for X\") or during onboarding entity seeding. For uncertain/brainstormed items, prefer suggest_work_items instead.",
 23→    inputSchema: z.object({
 24→      kind: z.enum(["task", "feature", "project"]).describe(
 25→        "project: named product area or workstream (MUST create before features/tasks can belong to it). feature: capability within an existing project. task: concrete executable work with action verb. If no projects exist yet, create a project first.",
 26→      ),
 27→      title: z.string().min(1).describe("Concise entity title"),
 28→      rationale: z.string().min(1).describe("Why this entity is needed — seeds the description"),
 29→      category: z.enum(ENTITY_CATEGORIES).optional().describe("Category classification"),
 30→      priority: z.enum(ENTITY_PRIORITIES).optional().describe("critical: blocking/urgent. high: important, needs attention soon. medium: normal priority. low: nice-to-have, deferred."),
 31→      project: z.string().optional().describe("Project name to scope the entity under"),
 32→    }),
 33→    execute: async (input, options) => {
 34→      const { context } = await requireAuthorizedContext(options, "create_task", deps);
 35→      const now = new Date();
 36→
 37→      const embedding = await createEmbeddingVector(
 38→        deps.embeddingModel,
 39→        input.title,
 40→        deps.embeddingDimension,
 41→      );
 42→
 43→      const entityId = randomUUID();
 44→
 45→      // Hard guard: never create a project with the same name as the workspace
 46→      if (input.kind === "project") {
 47→        const [ws] = await deps.surreal.query<[{ name: string } | undefined]>(
 48→          "SELECT name FROM ONLY $ws;",
 49→          { ws: context.workspaceRecord },
 50→        );
 51→        if (ws && input.title.toLowerCase().trim() === ws.name.toLowerCase().trim()) {
 52→          return {
 53→            error: `"${input.title}" is the workspace name, not a project. Create the user's described items (e.g. Dashboard, Inventory) as projects instead.`,
 54→          };
 55→        }
 56→
 57→        const projectRecord = await createProjectRecord({
 58→          surreal: deps.surreal,
 59→          name: input.title,
 60→          status: "active",
 61→          now,
 62→          workspaceRecord: context.workspaceRecord,
 63→          sourceMessageRecord: context.currentMessageRecord,
 64→        });
 65→
 66→        if (embedding) {
 67→          await deps.surreal.update(projectRecord).merge({ embedding });
 68→        }
 69→
