273→  await fetch(`${baseUrl}/api/auth/jwks`);
274→
275→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
276→    method: "POST",
277→    headers: { "Content-Type": "application/json" },
278→    body: JSON.stringify({
279→      client_name: `smoke-test-${Date.now()}`,
280→      redirect_uris: ["http://127.0.0.1:9999/callback"],
281→      grant_types: ["authorization_code", "refresh_token"],
282→      response_types: ["code"],
283→      token_endpoint_auth_method: "none",
284→    }),
285→  });
286→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
287→
288→  const { client_id } = (await dcrRes.json()) as { client_id: string };
289→
290→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
291→    cid: client_id,
292→  });
293→
294→  const { verifier, challenge } = generatePkce();
295→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
296→  authUrl.searchParams.set("client_id", client_id);
297→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
298→  authUrl.searchParams.set("response_type", "code");
299→  authUrl.searchParams.set("scope", scopes);
300→  authUrl.searchParams.set("state", "test-state");
301→  authUrl.searchParams.set("code_challenge", challenge);
302→  authUrl.searchParams.set("code_challenge_method", "S256");
303→  authUrl.searchParams.set("resource", baseUrl);
304→
305→  const authRes = await fetch(authUrl.toString(), {
306→    headers: sessionHeaders,
307→    redirect: "manual",
308→  });
309→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
310→
311→  const location = authRes.headers.get("location")!;
312→  const redirectUrl = new URL(location, baseUrl);
313→  const code = redirectUrl.searchParams.get("code") ?? "";
314→  if (!code) throw new Error(`No code in redirect: ${location}`);
315→
316→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
317→    method: "POST",
318→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
319→    body: new URLSearchParams({
320→      grant_type: "authorization_code",
321→      code,
322→      redirect_uri: "http://127.0.0.1:9999/callback",
323→      client_id,
324→      code_verifier: verifier,
325→      resource: baseUrl,
326→    }),
327→  });
328→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
329→
330→  const tokens = (await tokenRes.json()) as { access_token: string };
331→  return tokens.access_token;
332→}
